mapper.select:
SELECT sa.id, sa.approval_no, sa.patient_id, sa.patient_name, p.patient_no, p.bed_no, sa.ward_id, sa.ward_name, sa.person_id, sa.person_name, sa.id_card, ap.phone, ap.relation, sa.approval_reason, sa.start_date, sa.end_date, sa.approval_status, sa.apply_user_id, sa.apply_user_name, sa.apply_time, sa.audit_user_id, sa.audit_user_name, sa.audit_time, sa.audit_remark FROM special_approval sa LEFT JOIN patient p ON sa.patient_id = p.id LEFT JOIN accompany_person ap ON sa.person_id = ap.id WHERE sa.deleted = 0
AND sa.ward_id = #{wardId}
AND sa.approval_status = #{approvalStatus}
AND sa.patient_name LIKE CONCAT('%', #{patientName}, '%')
AND sa.person_name LIKE CONCAT('%', #{personName}, '%')
ORDER BY sa.apply_time DESC
